"use client";

import dynamic from "next/dynamic";
import type { Video } from "@/lib/videos";

const MuxPlayer = dynamic(() => import("@mux/mux-player-react"), {
  ssr: false,
});

export function VideoCard({
  video,
  unlocked,
  onLockedClick,
}: {
  video: Video;
  unlocked: boolean;
  onLockedClick: () => void;
}) {
  return (
    <article
      className="video-card"
      onClick={unlocked ? undefined : onLockedClick}
    >
      <div className={`video-thumb ${unlocked ? "" : "locked"}`}>
        <div className="poster" />
        {unlocked ? (
          video.playbackId ? (
            <MuxPlayer
              playbackId={video.playbackId}
              streamType="on-demand"
              style={{ position: "absolute", inset: 0, width: "100%" }}
              metadata={{ video_title: video.title }}
            />
          ) : (
            <div className="lock-overlay">
              <span className="icon">▶</span>
              <span className="label">Demo Asset</span>
            </div>
          )
        ) : (
          <div className="lock-overlay">
            <span className="icon">🔒</span>
            <span className="label">Members Only</span>
          </div>
        )}
      </div>
      <div className="video-meta">
        <h3>{video.title}</h3>
        <p>{video.description}</p>
        <time dateTime={video.date}>
          {new Date(video.date).toLocaleDateString(undefined, {
            year: "numeric",
            month: "short",
            day: "numeric",
          })}
        </time>
      </div>
    </article>
  );
}

