import { NextRequest, NextResponse } from "next/server";
import Stripe from "stripe";
import { stripe, stripeConfigured } from "@/lib/stripe";
import { mintMembership } from "@/lib/mint";

export const runtime = "nodejs";

export async function POST(req: NextRequest) {
  if (!stripeConfigured || !stripe) {
    return NextResponse.json({ demo: true });
  }

  const secret = process.env.STRIPE_WEBHOOK_SECRET;
  const sig = req.headers.get("stripe-signature");
  const raw = await req.text();

  let event: Stripe.Event;
  try {
    event =
      secret && sig
        ? stripe.webhooks.constructEvent(raw, sig, secret)
        : (JSON.parse(raw) as Stripe.Event);
  } catch (e) {
    return NextResponse.json({ error: "Invalid signature" }, { status: 400 });
  }

  if (
    event.type === "invoice.payment_succeeded" ||
    event.type === "checkout.session.completed"
  ) {
    const obj = event.data.object as { metadata?: Record<string, string> };
    const wallet = obj.metadata?.walletAddress;
    if (wallet) {
      await mintMembership(wallet).catch((e) =>
        console.error("[webhook] mint failed:", e)
      );
    }
  }

  return NextResponse.json({ received: true });
}

