import {
  createThirdwebClient,
  getContract,
  prepareContractCall,
  sendTransaction,
} from "thirdweb";
import { base } from "thirdweb/chains";
import { privateKeyToAccount } from "thirdweb/wallets";

/**
 * Server-side mint of a MembershipPass to `to` on Base.
 * No-ops (with a log) if backend keys/contract aren't configured yet.
 */
export async function mintMembership(to: string): Promise<void> {
  const secretKey = process.env.THIRDWEB_SECRET_KEY;
  const pk = process.env.BACKEND_WALLET_PK;
  const address = process.env.NEXT_PUBLIC_MEMBERSHIP_CONTRACT;

  if (!secretKey || !pk || !address) {
    console.log(
      `[mint] skipped for ${to} — THIRDWEB_SECRET_KEY / BACKEND_WALLET_PK / MEMBERSHIP_CONTRACT not set`
    );
    return;
  }

  const client = createThirdwebClient({ secretKey });
  const account = privateKeyToAccount({ client, privateKey: pk });
  const contract = getContract({ client, chain: base, address });

  const tx = prepareContractCall({
    contract,
    method: "function ownerMint(address to)",
    params: [to],
  });

  const { transactionHash } = await sendTransaction({
    account,
    transaction: tx,
  });
  console.log(`[mint] MembershipPass minted to ${to}: ${transactionHash}`);
}

