"use client";

import { ConnectButton } from "thirdweb/react";
import { inAppWallet } from "thirdweb/wallets";
import { client, chain, thirdwebConfigured } from "@/lib/thirdweb";
import { useState } from "react";

const wallets = [
  inAppWallet({
    auth: { options: ["google", "apple", "email", "passkey", "facebook"] },
  }),
];

/**
 * ThirdWeb social-login embedded wallet.
 * Falls back to a demo "Sign in" button when NEXT_PUBLIC_THIRDWEB_CLIENT_ID
 * isn't set, so the page remains clickable end-to-end.
 */
export function ConnectWallet({
  onDemoConnect,
}: {
  onDemoConnect?: () => void;
}) {
  const [demoConnected, setDemoConnected] = useState(false);

  if (!thirdwebConfigured) {
    return (
      <button
        className="btn btn-outline"
        onClick={() => {
          setDemoConnected(true);
          onDemoConnect?.();
        }}
      >
        {demoConnected ? "0xDEMO…1234" : "Sign in"}
      </button>
    );
  }

  return (
    <ConnectButton
      client={client}
      chain={chain}
      wallets={wallets}
      connectButton={{ label: "Sign in" }}
      connectModal={{
        title: "Sign in",
        size: "compact",
        showThirdwebBranding: false,
      }}
      theme="light"
    />
  );
}

