import { createThirdwebClient } from "thirdweb";
import { base } from "thirdweb/chains";

export const thirdwebClientId = process.env.NEXT_PUBLIC_THIRDWEB_CLIENT_ID;
export const thirdwebConfigured = !!thirdwebClientId;

// Client is created even with an empty id so the provider tree mounts; UI
// components check `thirdwebConfigured` before rendering real connect flows.
export const client = createThirdwebClient({
  clientId: thirdwebClientId || "demo",
});

export const chain = base; // Base mainnet (8453)

export const MEMBERSHIP_CONTRACT =
  process.env.NEXT_PUBLIC_MEMBERSHIP_CONTRACT || "";

