"use client";

import { useState } from "react";
import { useActiveAccount, useConnectModal } from "thirdweb/react";
import { inAppWallet } from "thirdweb/wallets";
import type { Video } from "@/lib/videos";
import { client, chain, thirdwebConfigured } from "@/lib/thirdweb";
import { VideoCard } from "@/components/VideoCard";
import { PaywallModal } from "@/components/PaywallModal";

export function VideoGrid({
  videos,
  unlocked,
}: {
  videos: Video[];
  unlocked: boolean;
}) {
  const account = useActiveAccount();
  const { connect } = useConnectModal();
  const [showPaywall, setShowPaywall] = useState(false);
  const [demoSignedIn, setDemoSignedIn] = useState(false);

  async function handleLockedClick() {
    // Require sign-in (ThirdWeb social wallet) before showing the paywall.
    if (thirdwebConfigured && !account) {
      try {
        await connect({
          client,
          chain,
          wallets: [
            inAppWallet({
              auth: { options: ["google", "apple", "email", "passkey"] },
            }),
          ],
          size: "compact",
          title: "Sign in to continue",
          showThirdwebBranding: false,
        });
        setShowPaywall(true);
      } catch {
        /* user dismissed */
      }
      return;
    }
    if (!thirdwebConfigured && !demoSignedIn) {
      // In demo mode, treat first click as "sign in", second opens paywall.
      setDemoSignedIn(true);
      setShowPaywall(true);
      return;
    }
    setShowPaywall(true);
  }

  return (
    <>
      <div className="video-grid">
        {videos.map((v) => (
          <VideoCard
            key={v.id}
            video={v}
            unlocked={unlocked}
            onLockedClick={handleLockedClick}
          />
        ))}
      </div>

      {showPaywall && !unlocked && (
        <PaywallModal
          walletAddress={account?.address}
          onClose={() => setShowPaywall(false)}
        />
      )}
    </>
  );
}

