"use client";

import { useEffect, useMemo, useState } from "react";
import { useRouter } from "next/navigation";
import { loadStripe, type Appearance } from "@stripe/stripe-js";
import {
  Elements,
  PaymentElement,
  useElements,
  useStripe,
} from "@stripe/react-stripe-js";

const PUBLISHABLE = process.env.NEXT_PUBLIC_STRIPE_PUBLISHABLE_KEY;
const stripePromise = PUBLISHABLE ? loadStripe(PUBLISHABLE) : null;

const appearance: Appearance = {
  theme: "stripe",
  variables: {
    fontFamily: "Arial, sans-serif",
    colorPrimary: "#111111",
    borderRadius: "8px",
  },
  rules: {
    ".Label": { fontFamily: "Arial, sans-serif" },
  },
};

function CheckoutForm() {
  const stripe = useStripe();
  const elements = useElements();
  const [busy, setBusy] = useState(false);
  const [err, setErr] = useState<string | null>(null);

  return (
    <form
      onSubmit={async (e) => {
        e.preventDefault();
        if (!stripe || !elements) return;
        setBusy(true);
        setErr(null);
        const { error } = await stripe.confirmPayment({
          elements,
          confirmParams: {
            return_url: `${window.location.origin}/videos?subscribed=1`,
          },
        });
        if (error) {
          setErr(error.message ?? "Payment failed");
          setBusy(false);
        }
      }}
    >
      <PaymentElement
        options={{
          layout: "tabs",
          wallets: { applePay: "auto", googlePay: "auto" },
        }}
      />
      {err && (
        <p style={{ color: "#b91c1c", fontSize: 13, marginTop: 10 }}>{err}</p>
      )}
      <button
        className="btn btn-primary"
        disabled={!stripe || busy}
        style={{ width: "100%", marginTop: 18 }}
      >
        {busy ? "Processing…" : "Subscribe"}
      </button>
    </form>
  );
}

export function PaywallModal({
  walletAddress,
  onClose,
}: {
  walletAddress?: string;
  onClose: () => void;
}) {
  const router = useRouter();
  const [clientSecret, setClientSecret] = useState<string | null>(null);
  const [demo, setDemo] = useState(!PUBLISHABLE);
  const [loading, setLoading] = useState(!!PUBLISHABLE);

  useEffect(() => {
    if (!PUBLISHABLE) return;
    fetch("/api/stripe/create-subscription", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ walletAddress }),
    })
      .then((r) => r.json())
      .then((d) => {
        if (d.demo) setDemo(true);
        else setClientSecret(d.clientSecret);
      })
      .catch(() => setDemo(true))
      .finally(() => setLoading(false));
  }, [walletAddress]);

  const options = useMemo(
    () => (clientSecret ? { clientSecret, appearance } : undefined),
    [clientSecret]
  );

  async function simulate() {
    await fetch("/api/access/demo", { method: "POST" });
    onClose();
    router.refresh();
  }

  return (
    <div className="modal-backdrop" onClick={onClose}>
      <div className="modal" onClick={(e) => e.stopPropagation()}>
        <button className="close" onClick={onClose} aria-label="Close">
          ×
        </button>

        <div className="kicker">Membership</div>
        <h2 className="headline">
          Unlock every video.
          <br />
          Cancel anytime.
        </h2>
        <p className="sub">
          Get unlimited access to our full library, plus a Membership Pass
          minted to your wallet on Base.
        </p>

        <div className="price-row">
          <span className="amount">$9</span>
          <span className="term">/ month</span>
        </div>

        <ul className="benefits">
          <li>Unlimited streaming of all member videos</li>
          <li>On-chain Membership Pass NFT (Base)</li>
          <li>New episodes every week</li>
        </ul>

        {demo ? (
          <>
            <div className="demo-banner">
              Demo mode — Stripe keys not configured. Use the button below to
              simulate a successful subscription.
            </div>
            <button
              className="btn btn-primary"
              style={{ width: "100%" }}
              onClick={simulate}
            >
              Simulate subscription
            </button>
          </>
        ) : loading ? (
          <p style={{ textAlign: "center", color: "#6b6b6b" }}>
            Loading secure checkout…
          </p>
        ) : options && stripePromise ? (
          <Elements stripe={stripePromise} options={options}>
            <CheckoutForm />
          </Elements>
        ) : null}

        <p className="fineprint">
          By subscribing you agree to our Terms. Renews monthly until
          cancelled.
        </p>
      </div>
    </div>
  );
}

