"use client";

import { useState } from "react";
import dynamic from "next/dynamic";
import Link from "next/link";

const MuxUploader = dynamic(() => import("@mux/mux-uploader-react"), {
  ssr: false,
});

type Stage = "idle" | "ready" | "uploading" | "saved";

export default function UploadsPage() {
  const [title, setTitle] = useState("");
  const [description, setDescription] = useState("");
  const [date, setDate] = useState(new Date().toISOString().slice(0, 10));
  const [endpoint, setEndpoint] = useState<string | null>(null);
  const [uploadId, setUploadId] = useState<string | null>(null);
  const [demo, setDemo] = useState(false);
  const [stage, setStage] = useState<Stage>("idle");
  const [msg, setMsg] = useState<string | null>(null);

  async function createUpload(e: React.FormEvent) {
    e.preventDefault();
    setMsg(null);
    const r = await fetch("/api/mux/upload", { method: "POST" });
    const d = await r.json();
    setUploadId(d.uploadId);
    if (d.demo) {
      setDemo(true);
      // No real upload possible — save metadata immediately.
      await saveVideo(d.uploadId, true);
    } else {
      setEndpoint(d.url);
      setStage("ready");
    }
  }

  async function saveVideo(id: string, isDemo: boolean) {
    const r = await fetch("/api/videos", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ title, description, date, uploadId: id, demo: isDemo }),
    });
    if (r.ok) {
      setStage("saved");
      setMsg(
        isDemo
          ? "Saved (demo mode — no file uploaded). It now appears on /videos."
          : "Upload complete and saved. Mux is processing the asset."
      );
    } else {
      setMsg("Failed to save video metadata.");
    }
  }

  return (
    <main className="container">
      <header style={{ padding: "36px 0 4px" }}>
        <h1 style={{ fontSize: 32 }}>Upload a video</h1>
        <p style={{ color: "var(--muted)" }}>
          Add a new members-only episode. Files are sent directly to Mux.
        </p>
      </header>

      <form className="upload-form" onSubmit={createUpload}>
        <label>
          Title
          <input
            required
            value={title}
            onChange={(e) => setTitle(e.target.value)}
            placeholder="Episode title"
          />
        </label>
        <label>
          Description
          <textarea
            required
            value={description}
            onChange={(e) => setDescription(e.target.value)}
            placeholder="What's this episode about?"
          />
        </label>
        <label>
          Date
          <input
            type="date"
            required
            value={date}
            onChange={(e) => setDate(e.target.value)}
          />
        </label>

        {stage === "idle" && (
          <button className="btn btn-primary" type="submit">
            Continue → Upload file
          </button>
        )}

        {stage === "ready" && endpoint && (
          <div>
            <p style={{ fontSize: 14, color: "var(--muted)", marginBottom: 8 }}>
              Drop your video file below.
            </p>
            <MuxUploader
              endpoint={endpoint}
              onUploadStart={() => setStage("uploading")}
              onSuccess={() => uploadId && saveVideo(uploadId, false)}
              style={{ width: "100%" }}
            />
          </div>
        )}

        {demo && stage !== "saved" && (
          <div className="demo-banner" style={{ marginTop: 8 }}>
            Demo mode — Mux keys not configured. Metadata saved without a
            file.
          </div>
        )}

        {msg && (
          <p style={{ fontSize: 14 }}>
            <span className="status-pill">{stage === "saved" ? "Saved" : "Info"}</span>{" "}
            {msg} <Link href="/videos">View on /videos →</Link>
          </p>
        )}
      </form>
    </main>
  );
}

