`contracts/MembershipPass.sol`:

```solidity
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import {ERC721} from "@openzeppelin/contracts/token/ERC721/ERC721.sol";
import {Ownable} from "@openzeppelin/contracts/access/Ownable.sol";

/**
 * @title MembershipPass
 * @notice Non-transferable ERC-721 minted to subscribers after a successful
 *         Stripe subscription. One pass per address. Owner (backend wallet)
 *         is the only minter; revoke() lets the owner burn a pass if a
 *         subscription is cancelled or charged back.
 *
 * Deploy to Base (chainId 8453) via:
 *   npx thirdweb deploy
 */
contract MembershipPass is ERC721, Ownable {
    uint256 private _nextId;
    string private _uri;

    /// @notice Whether an address has ever been minted a pass.
    mapping(address => bool) public hasPass;

    error AlreadyMember();
    error Soulbound();

    event MembershipMinted(address indexed to, uint256 indexed tokenId);
    event MembershipRevoked(address indexed from, uint256 indexed tokenId);

    constructor(
        string memory baseURI,
        address initialOwner
    ) ERC721("Membership Pass", "MEMBER") Ownable(initialOwner) {
        _uri = baseURI;
    }

    /// @notice Mint a pass to `to`. Backend-only (called from Stripe webhook).
    function ownerMint(address to) external onlyOwner returns (uint256) {
        if (hasPass[to]) revert AlreadyMember();
        hasPass[to] = true;
        uint256 tokenId = _nextId++;
        _safeMint(to, tokenId);
        emit MembershipMinted(to, tokenId);
        return tokenId;
    }

    /// @notice Burn a member's pass (e.g. subscription cancelled).
    function revoke(uint256 tokenId) external onlyOwner {
        address holder = _ownerOf(tokenId);
        hasPass[holder] = false;
        _burn(tokenId);
        emit MembershipRevoked(holder, tokenId);
    }

    function setBaseURI(string calldata uri) external onlyOwner {
        _uri = uri;
    }

    function _baseURI() internal view override returns (string memory) {
        return _uri;
    }

    /// @dev Soulbound: block transfers between non-zero addresses.
    function _update(
        address to,
        uint256 tokenId,
        address auth
    ) internal override returns (address) {
        address from = _ownerOf(tokenId);
        if (from != address(0) && to != address(0)) revert Soulbound();
        return super._update(to, tokenId, auth);
    }
}
```

**Design choices (open for review):**
- **OpenZeppelin v5** `ERC721` + `Ownable` — standard, audited, easy to extend.
- **`ownerMint(address)`** — only your backend wallet (the `owner`) can mint, called from the Stripe webhook (`lib/mint.ts`). One pass per address enforced by `hasPass`.
- **`revoke(tokenId)`** — burn a pass when a subscription is cancelled / refunded, so on-chain state tracks Stripe.
- **Soulbound** — `_update` override blocks user-to-user transfers (mint and burn still work). Drop that override if you want passes to be tradeable.
- **`setBaseURI`** — update token metadata/art later without redeploying.

**Deploy:** `npx thirdweb deploy` from the repo root → pick **Base** → set `initialOwner` to your `BACKEND_WALLET_PK` address → copy the deployed address into `NEXT_PUBLIC_MEMBERSHIP_CONTRACT`.

Want any changes — e.g. make it transferable, add ERC-5192 locked interface, or store an `expiresAt` timestamp per token for subscription expiry?

